/* global console, process */
import { spawn } from 'node:child_process';
import { existsSync } from 'node:fs';
import path from 'node:path';
import { performance } from 'node:perf_hooks';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const gnosisDir = path.resolve(__dirname, '../..');
const repoRoot = path.resolve(gnosisDir, '../..');
const beckyPath =
  process.env.GNOSIS_BECKY_PATH ??
  path.resolve(gnosisDir, 'polyglot/target/release/becky');

const examples = [
  {
    name: 'echo.gg',
    sourcePath: path.resolve(__dirname, 'echo.gg'),
  },
  {
    name: 'fib.gg',
    sourcePath: path.resolve(__dirname, 'fib.gg'),
  },
  {
    name: 'fanout.gg',
    sourcePath: path.resolve(__dirname, 'fanout.gg'),
  },
];

function readNumberSetting(flagName, envName, fallback) {
  const rawFlag = process.argv
    .slice(2)
    .find((value) => value.startsWith(`--${flagName}=`));
  const rawValue =
    rawFlag?.slice(flagName.length + 3) ??
    process.env[envName] ??
    `${fallback}`;
  const parsed = Number.parseInt(rawValue, 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

const warmupRuns = readNumberSetting(
  'warmup',
  'GNODE_BECKY_TOPOLOGY_SHOOTOUT_WARMUP',
  1
);
const measuredRuns = readNumberSetting(
  'iterations',
  'GNODE_BECKY_TOPOLOGY_SHOOTOUT_ITERATIONS',
  10
);

function percentile(sorted, ratio) {
  if (sorted.length === 0) {
    return 0;
  }

  const index = Math.min(
    sorted.length - 1,
    Math.max(0, Math.floor(sorted.length * ratio))
  );
  return sorted[index] ?? 0;
}

function summarize(samples) {
  const sorted = [...samples].sort((left, right) => left - right);
  const total = samples.reduce((sum, value) => sum + value, 0);
  return {
    meanMs: total / Math.max(1, samples.length),
    p50Ms: percentile(sorted, 0.5),
    p95Ms: percentile(sorted, 0.95),
    maxMs: sorted[sorted.length - 1] ?? 0,
  };
}

async function runBecky(example) {
  return await new Promise((resolve, reject) => {
    const child = spawn(beckyPath, [example.sourcePath, '--summary'], {
      cwd: repoRoot,
      env: process.env,
      stdio: ['ignore', 'pipe', 'pipe'],
    });

    let stdout = '';
    let stderr = '';

    child.stdout.setEncoding('utf8');
    child.stderr.setEncoding('utf8');
    child.stdout.on('data', (chunk) => {
      stdout += chunk;
    });
    child.stderr.on('data', (chunk) => {
      stderr += chunk;
    });
    child.once('error', reject);
    child.once('close', (code) => {
      resolve({
        exitCode: code ?? -1,
        stdout,
        stderr,
      });
    });
  });
}

async function measureTopology(example) {
  for (let run = 0; run < warmupRuns; run += 1) {
    const warmup = await runBecky(example);
    if (warmup.exitCode !== 0) {
      throw new Error(`becky failed warmup for ${example.name}:\n${warmup.stderr}`);
    }
    if (!warmup.stdout.includes(`${example.name}:`)) {
      throw new Error(
        `becky produced unexpected summary for ${example.name}: '${warmup.stdout.trim()}'`
      );
    }
  }

  const samples = [];
  for (let run = 0; run < measuredRuns; run += 1) {
    const started = performance.now();
    const result = await runBecky(example);
    const elapsedMs = performance.now() - started;
    if (result.exitCode !== 0) {
      throw new Error(`becky failed for ${example.name}:\n${result.stderr}`);
    }
    if (!result.stdout.includes(`${example.name}:`)) {
      throw new Error(
        `becky produced unexpected summary for ${example.name}: '${result.stdout.trim()}'`
      );
    }
    samples.push(elapsedMs);
  }

  return summarize(samples);
}

async function main() {
  if (!existsSync(beckyPath)) {
    throw new Error(
      `Missing ${beckyPath}; build polyglot release binaries before running this shootout.`
    );
  }

  console.log('becky topology analysis shootout');
  console.log(`warmup=${warmupRuns} measured=${measuredRuns}`);

  for (const example of examples) {
    const summary = await measureTopology(example);
    console.log(
      [
        example.name.padEnd(18),
        `mean=${summary.meanMs.toFixed(2)}ms`,
        `p50=${summary.p50Ms.toFixed(2)}ms`,
        `p95=${summary.p95Ms.toFixed(2)}ms`,
        `max=${summary.maxMs.toFixed(2)}ms`,
      ].join(' | ')
    );
  }
}

main().catch((error) => {
  const message =
    error instanceof Error ? error.stack ?? error.message : String(error);
  process.stderr.write(`${message}\n`);
  process.exitCode = 1;
});
